#include <stdio.h>
#include <inttypes.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int N; scanf("%d", &N);
        unsigned long long sum = 0, mn = (unsigned long long)(-1), mx = 0;
        for(int i=0;i<N;i++){
            unsigned long long x; scanf("%llu", &x);
            sum += x;
            if(x < mn) mn = x;
            if(x > mx) mx = x;
        }
        unsigned long long ans = sum - mx + (mx % mn);
        printf("%llu\n", ans);
    }
    return 0;
}

