#!/usr/bin/env python3
import sys

def main():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        N = int(next(it))
        total = 0
        mn = 10**18
        mx = 0
        for _ in range(N):
            x = int(next(it))
            total += x
            if x < mn:
                mn = x
            if x > mx:
                mx = x
        ans = total - mx + (mx % mn)
        out_lines.append(str(ans))
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    main()

